den cross dates where series1 crosses above series2\"\"\"\n46\t    crosses = []\n47\t    for i in range(1, len(series1)):\n48\t        if pd.notna(series1.iloc[i]) and pd.notna(series2.iloc[i]) and \\\n49\t           pd.notna(series1.iloc[i-1]) and pd.notna(series2.iloc[i-1]):\n50\t            # Golden cross: previous day series1 <= series2, current day series1 > series2\n51\t            if series1.iloc[i-1] <= series2.iloc[i-1] and series1.iloc[i] > series2.iloc[i]:\n52\t                crosses.append(series1.index[i])\n53\t    return crosses\n54\t\n55\tdef check_triple_cross_within_window(macd_dates: List, kdj_dates: List, ma_dates: List, window_days=5) -> Optional[Tuple]:\n56\t    \"\"\"Check if three golden crosses occur within a window of 5 trading days\"\"\"\n57\t    for macd_date in macd_dates:\n58\t        for kdj_date in kdj_dates:\n59\t            for ma_date in ma_dates:\n60\t                dates = [macd_date, kdj_date, ma_date]\n61\t                dates_sorted = sorted(dates)\n62\t\n63\t                # Calculate trading day difference (approximate: 5 trading days ≈ 7 calendar days)\n64\t                first_date = pd.to_datetime(dates_sorted[0])\n65\t                last_date = pd.to_datetime(dates_sorted[-1])\n66\t\n67\t                if (last_date - first_date).days <= 7:\n68\t                    return (macd_date, kdj_date, ma_date)\n69\t    return None\n70\t\n71\tdef generate_sample_data(stock_code: str, base_price: float = 20.0) -> pd.DataFrame:\n72\t    \"\"\"Generate sample stock data with golden cross patterns\"\"\"\n73\t    dates = pd.date_range(start='2024-05-01', end='2024-07-31', freq='B')\n74\t    np.random.seed(int(stock_code[3:]))\n75\t\n76\t    # Generate price data with upward trend for golden cross\n77\t    trend = np.linspace(0, 5, len(dates))\n78\t    noise = np.random.randn(len(dates)) * 0.5\n79\t    close = base_price + trend + noise\n80\t\n81\t    # Add some volatility\n82\t    high = close + np.abs(np.random.randn(len(dates)